  1→/**
  2→ * Tool Registry Initialization
  3→ *
  4→ * Registers all tool renderers on app startup.
  5→ * Import this file early in your app to ensure tools are registered.
  6→ */
  7→
  8→import { toolRegistry } from "./ToolRegistry";
  9→import {
 10→  DefaultToolRenderer,
 11→  EditToolRenderer,
 12→  WriteToolRenderer,
 13→  BashToolRenderer,
 14→  ReadToolRenderer,
 15→  GrepToolRenderer,
 16→  TodoWriteToolRenderer,
 17→  GlobToolRenderer,
 18→  BashOutputToolRenderer,
 19→  MultiEditToolRenderer,
 20→  WebFetchToolRenderer,
 21→  WebSearchToolRenderer,
 22→  KillShellToolRenderer,
 23→  TaskToolRenderer,
 24→  LSToolRenderer,
 25→  // OpenDevs MCP — Browser automation
 26→  BrowserSnapshotToolRenderer,
 27→  BrowserNavigateToolRenderer,
 28→  BrowserNavigateBackToolRenderer,
 29→  BrowserClickToolRenderer,
 30→  BrowserTypeToolRenderer,
 31→  BrowserPressKeyToolRenderer,
 32→  BrowserHoverToolRenderer,
 33→  BrowserSelectOptionToolRenderer,
 34→  BrowserWaitForToolRenderer,
 35→  BrowserEvaluateToolRenderer,
 36→  BrowserConsoleMessagesToolRenderer,
 37→  BrowserScreenshotToolRenderer,
 38→  BrowserNetworkRequestsToolRenderer,
 39→  BrowserScrollToolRenderer,
 40→  // OpenDevs MCP — Workspace
 41→  AskUserQuestionToolRenderer,
 42→  GetWorkspaceDiffToolRenderer,
 43→  DiffCommentToolRenderer,
 44→  GetTerminalOutputToolRenderer,
 45→} from "./renderers";
 46→
 47→// Idempotency guard - prevent double registration during HMR/dev
 48→let __didRegisterTools = false;
 49→
 50→/**
 51→ * Initialize all tool renderers
 52→ * Idempotent - safe to call multiple times
 53→ */
 54→export function registerAllTools() {
 55→  if (__didRegisterTools) return;
 56→  __didRegisterTools = true;
 57→
 58→  // Set default renderer (fallback for unknown tools)
 59→  toolRegistry.setDefault(DefaultToolRenderer);
 60→
 61→  // Register specific tool renderers
