  1→/**
  2→ * Session and message-related TypeScript type definitions
  3→ * Types for Claude Code session management and message handling
  4→ */
  5→
  6→// Canonical enum types — defined as Zod schemas in shared/enums.ts,
  7→// imported here for local use and re-exported for backwards compat.
  8→import type { MessageRole, SessionStatus } from "../enums";
  9→import type {
 10→  EnterPlanModeNotification as SessionEnterPlanModeEvent,
 11→  ErrorResponse as SessionErrorEvent,
 12→  MessageResponse as SessionMessageEvent,
 13→  SessionNotification,
 14→  StatusChangedNotification as SessionStatusEvent,
 15→} from "../session-events";
 16→export type { MessageRole, SessionStatus };
 17→export type {
 18→  SessionMessageEvent,
 19→  SessionErrorEvent,
 20→  SessionEnterPlanModeEvent,
 21→  SessionStatusEvent,
 22→  SessionNotification,
 23→};
 24→
 25→/**
 26→ * Base message entity
 27→ * Core structure for all chat messages in a session
 28→ * Matches the messages database table schema (id = UUID7, embeds created_at)
 29→ */
 30→export interface Message {
 31→  id: string;
 32→  session_id: string;
 33→  seq: number; // Per-session monotonic sequence number (auto-assigned by trigger)
 34→  role: MessageRole;
 35→  content: string; // JSON-stringified MessageContent
 36→  turn_id?: string | null; // Conversation turn identifier
 37→  sent_at?: string | null; // ISO timestamp when message sent to Claude
 38→  cancelled_at?: string | null; // ISO timestamp when user cancels message
 39→  model?: string | null; // Claude model used (e.g., 'sonnet')
 40→  agent_message_id?: string | null; // Agent SDK-provided message identifier
 41→  parent_tool_use_id?: string | null; // Subagent parent task ID (promoted from JSON envelope)
 42→}
 43→
 44→/**
 45→ * Parsed message content structure
 46→ * Content blocks can be text, tool_use, tool_result, or thinking
 47→ */
 48→export type MessageContent = ContentBlock[];
 49→
 50→export type ContentBlock = TextBlock | ImageBlock | ToolUseBlock | ToolResultBlock | ThinkingBlock;
 51→
 52→/**
 53→ * Text content block
 54→ */
 55→export interface TextBlock {
 56→  type: "text";
 57→  text: string;
 58→}
 59→
 60→/**
 61→ * Image content block (Anthropic API format)
 62→ * Used for user-pasted images sent to Claude's vision API
 63→ */
 64→export interface ImageBlock {
 65→  type: "image";
 66→  source: {
 67→    type: "base64";
 68→    media_type: string;
 69→    data: string;
 70→  };
 71→}
 72→
 73→/**
 74→ * Tool invocation block
 75→ * Represents a Claude Code tool being called
 76→ */
 77→export interface ToolUseBlock {
 78→  type: "tool_use";
 79→  id: string;
 80→  name: string;
 81→  input: Record<string, any>;
 82→}
 83→
 84→/**
 85→ * Tool result block
 86→ * Contains the output from a tool execution
 87→ */
 88→export interface ToolResultBlock {
 89→  type: "tool_result";
 90→  tool_use_id: string;
 91→  content: string | Record<string, any>;
 92→  is_error?: boolean;
 93→}
 94→
 95→export function isTextBlock(block: ContentBlock | string): block is TextBlock {
 96→  return typeof block === "object" && block !== null && block.type === "text";
 97→}
 98→
 99→export function isImageBlock(block: ContentBlock | string): block is ImageBlock {
100→  return typeof block === "object" && block !== null && block.type === "image";
101→}
102→
103→export function isToolUseBlock(block: ContentBlock | string): block is ToolUseBlock {
104→  return typeof block === "object" && block !== null && block.type === "tool_use";
105→}
106→
107→export function isToolResultBlock(block: ContentBlock | string): block is ToolResultBlock {
108→  return typeof block === "object" && block !== null && block.type === "tool_result" && "tool_use_id" in block;
109→}
110→
111→export function isThinkingBlock(block: ContentBlock | string): block is ThinkingBlock {
112→  return typeof block === "object" && block !== null && block.type === "thinking";
113→}
114→
115→/**
116→ * Thinking block
117→ * Contains Claude's internal reasoning process
118→ * Encrypted with signature for verification
119→ */
120→export interface ThinkingBlock {
