 1→/**
 2→ * Turn Statistics Calculator
 3→ *
 4→ * Analyzes assistant turn messages to extract aggregated statistics:
 5→ * - Tool call counts (total and per-subagent)
 6→ * - File changes (unique files affected)
 7→ *
 8→ * Used by AssistantTurn component to display collapsed summary.
 9→ */
10→
11→import type { Message, ContentBlock } from "@/shared/types";
12→import { isToolUseBlock } from "@shared/types/session";
13→
14→export interface TurnStats {
15→  toolCount: number;
16→  subagentCount: number;
17→  filesChanged: number;
18→}
19→
20→interface ParseContentFn {
21→  (content: string): (ContentBlock | string)[] | string | null;
22→}
23→
24→/**
25→ * Calculate statistics for an assistant turn
26→ *
27→ * @param messages - Array of assistant messages in this turn
28→ * @param parseContent - Function to parse message content JSON
29→ * @returns Aggregated statistics for the turn
30→ */
31→export function calculateTurnStats(messages: Message[], parseContent: ParseContentFn): TurnStats {
32→  let toolCount = 0;
33→  let subagentCount = 0;
34→  const fileSet = new Set<string>();
35→
36→  for (const message of messages) {
37→    const contentBlocks = parseContent(message.content);
38→    if (!Array.isArray(contentBlocks)) continue;
39→
40→    for (const block of contentBlocks) {
41→      if (typeof block === "string") continue;
42→      if (!isToolUseBlock(block)) continue;
43→
44→      toolCount++;
45→
46→      if (block.name === "Task" || block.name === "Agent") {
47→        subagentCount++;
48→      }
49→
50→      if (block.input?.file_path) {
51→        fileSet.add(block.input.file_path);
52→      }
53→    }
54→  }
55→
56→  return { toolCount, subagentCount, filesChanged: fileSet.size };
57→}
